const AWS = require('aws-sdk');
const { execFile } = require('child_process');
const { promisify } = require('util');
const fs = require('fs').promises;
const path = require('path');
const crypto = require('crypto');

const execFileAsync = promisify(execFile);
const s3 = new AWS.S3();

const ALLOWED_INPUT_FORMATS = ['jpg', 'jpeg', 'png', 'gif', 'webp', 'bmp', 'tiff'];
const ALLOWED_OUTPUT_FORMATS = ['jpg', 'jpeg', 'png', 'gif', 'webp', 'bmp'];
const MAX_FILE_SIZE = 50 * 1024 * 1024;
const IMAGEMAGICK_TIMEOUT = 30000;

const ALLOWED_CONVERT_OPTIONS = {
  resize: /^\d{1,5}x\d{1,5}$/,
  quality: /^([1-9]|[1-9]\d|100)$/,
  rotate: /^(90|180|270)$/
};

function validateS3Key(key) {
  if (!key || typeof key !== 'string') {
    throw new Error('Invalid S3 key');
  }
  
  if (key.length > 1024) {
    throw new Error('S3 key too long');
  }
  
  if (key.includes('..') || key.includes('//')) {
    throw new Error('Invalid S3 key path');
  }
  
  const normalizedKey = path.normalize(key);
  if (normalizedKey.startsWith('..') || normalizedKey.startsWith('/')) {
    throw new Error('Invalid S3 key path traversal detected');
  }
  
  return normalizedKey;
}

function validateFormat(format, allowedFormats) {
  if (!format || typeof format !== 'string') {
    throw new Error('Invalid format');
  }
  
  const normalizedFormat = format.toLowerCase().trim();
  
  if (!allowedFormats.includes(normalizedFormat)) {
    throw new Error(`Format not allowed: ${normalizedFormat}`);
  }
  
  return normalizedFormat;
}

function validateConvertOptions(options) {
  if (!options || typeof options !== 'object') {
    return {};
  }
  
  const validatedOptions = {};
  
  for (const [key, value] of Object.entries(options)) {
    if (ALLOWED_CONVERT_OPTIONS[key]) {
      if (typeof value === 'string' && ALLOWED_CONVERT_OPTIONS[key].test(value)) {
        validatedOptions[key] = value;
      }
    }
  }
  
  return validatedOptions;
}

function getFileExtension(filename) {
  const ext = path.extname(filename).toLowerCase().slice(1);
  return ext;
}

function generateSafeTempPath(prefix = 'img') {
  const randomName = crypto.randomBytes(16).toString('hex');
  return path.join('/tmp', `${prefix}_${randomName}`);
}

async function downloadFromS3(bucket, key, localPath) {
  const params = {
    Bucket: bucket,
    Key: key
  };
  
  const headData = await s3.headObject(params).promise();
  
  if (headData.ContentLength > MAX_FILE_SIZE) {
    throw new Error('File size exceeds maximum allowed size');
  }
  
  const data = await s3.getObject(params).promise();
  await fs.writeFile(localPath, data.Body);
  
  return data.ContentType;
}

async function uploadToS3(bucket, key, localPath, contentType) {
  const fileContent = await fs.readFile(localPath);
  
  const params = {
    Bucket: bucket,
    Key: key,
    Body: fileContent,
    ContentType: contentType,
    ServerSideEncryption: 'AES256'
  };
  
  await s3.putObject(params).promise();
}

async function convertImage(inputPath, outputPath, outputFormat, options) {
  const args = [inputPath];
  
  if (options.resize) {
    args.push('-resize', options.resize);
  }
  
  if (options.quality) {
    args.push('-quality', options.quality);
  }
  
  if (options.rotate) {
    args.push('-rotate', options.rotate);
  }
  
  args.push('-strip');
  args.push('-limit', 'memory', '256MiB');
  args.push('-limit', 'map', '512MiB');
  args.push('-limit', 'disk', '1GiB');
  args.push('-limit', 'thread', '2');
  
  args.push(`${outputFormat}:${outputPath}`);
  
  try {
    const { stdout, stderr } = await execFileAsync('/usr/bin/convert', args, {
      timeout: IMAGEMAGICK_TIMEOUT,
      maxBuffer: 10 * 1024 * 1024,
      env: {
        PATH: '/usr/bin:/bin',
        MAGICK_TMPDIR: '/tmp'
      }
    });
    
    return { stdout, stderr };
  } catch (error) {
    throw new Error(`ImageMagick conversion failed: ${error.message}`);
  }
}

async function cleanupFiles(files) {
  for (const file of files) {
    try {
      await fs.unlink(file);
    } catch (error) {
      console.error(`Failed to cleanup file ${file}:`, error.message);
    }
  }
}

exports.handler = async (event) => {
  const filesToCleanup = [];
  
  try {
    if (!event.Records || !Array.isArray(event.Records) || event.Records.length === 0) {
      throw new Error('Invalid event structure');
    }
    
    const record = event.Records[0];
    
    if (!record.s3 || !record.s3.bucket || !record.s3.object) {
      throw new Error('Invalid S3 event structure');
    }
    
    const sourceBucket = record.s3.bucket.name;
    const sourceKey = decodeURIComponent(record.s3.object.key.replace(/\+/g, ' '));
    
    const validatedSourceKey = validateS3Key(sourceKey);
    
    const outputFormat = record.s3.object.metadata?.outputFormat || 
                        event.outputFormat || 
                        'jpg';
    const validatedOutputFormat = validateFormat(outputFormat, ALLOWED_OUTPUT_FORMATS);
    
    const convertOptions = validateConvertOptions(
      record.s3.object.metadata?.convertOptions || event.convertOptions || {}
    );
    
    const inputExtension = getFileExtension(validatedSourceKey);
    validateFormat(inputExtension, ALLOWED_INPUT_FORMATS);
    
    const destinationBucket = process.env.DESTINATION_BUCKET || sourceBucket;
    const destinationPrefix = process.env.DESTINATION_PREFIX || 'converted/';
    
    const inputPath = generateSafeTempPath('input');
    const outputPath = generateSafeTempPath('output');
    filesToCleanup.push(inputPath, outputPath);
    
    await downloadFromS3(sourceBucket, validatedSourceKey, inputPath);
    
    await convertImage(inputPath, outputPath, validatedOutputFormat, convertOptions);
    
    const baseFilename = path.basename(validatedSourceKey, path.extname(validatedSourceKey));
    const destinationKey = `${destinationPrefix}${baseFilename}.${validatedOutputFormat}`;
    
    const contentType = `image/${validatedOutputFormat === 'jpg' ? 'jpeg' : validatedOutputFormat}`;
    await uploadToS3(destinationBucket, destinationKey, outputPath, contentType);
    
    await cleanupFiles(filesToCleanup);
    
    return {
      statusCode: 200,
      body: JSON.stringify({
        message: 'Image converted successfully',
        sourceKey: validatedSourceKey,
        destinationKey: destinationKey,
        format: validatedOutputFormat
      })
    };
    
  } catch (error) {
    await cleanupFiles(filesToCleanup);
    
    console.error('Error processing image:', error.message);
    
    return {
      statusCode: 500,
      body: JSON.stringify({
        message: 'Image conversion failed',
        error: error.message
      })
    };
  }
};